        </div>
        <div class="title">场馆管理</div>
        <div class="venues">
            <div v-if="exist_data">
                <div class="items" v-for="venue in venues.data" :key="venue.id">
                    <van-swipe-cell>
                        <div class="item" @click="goToPage('/adminVenueDetail/' + venue.id)">
                            <div class="left">
                                <img :src="venue.pic" alt="">
                            </div>
                            <div class="right">
                                <div class="name">{{ venue.name }}</div>
                                <div class="tags">
                                    <van-tag round type="primary">快速订场</van-tag>
                                    <van-tag plain type="primary">有停车场</van-tag>
                                    <van-tag plain type="primary">木质地板</van-tag>
                                </div>
                                <div class="priceandbook">
                                    <div class="price">
                                        {{ venue.price }} 元/小时/场
                                    </div>
                                    <div class="button">
                                        <van-button round type="primary">管理</van-button>
                                    </div>
                                </div>

                            </div>

                        </div>
                        <template #right>
                            <van-button square type="danger" text="下架" style="height: 100%;" @click="deleteVenue(venue.id)"/>
                        </template>
                    </van-swipe-cell>
                </div>
                <van-back-top right="15vw" bottom="10vh" />
            </div>
            <div v-else>
                <p><van-empty description="暂未开放，敬请期待" /></p>
            </div>
        </div>

        <!-- 圆角弹窗（居中） -->
        <van-popup v-model:show="showAddNewVenue" round :style="{ padding: '1px' }">
            <div class="addNewVenue information">
                <div class="AddVenueTitle">添加新场馆</div>
                <van-cell-group inset>
                    <van-form @submit="addNewVenue" style="padding-top:0px">
                        <van-field name="uploader" label="场地图片">
                            <template #input>
                                <van-uploader v-model="picNewValue" />
                            </template>
                        </van-field>
                        <van-field v-model="NewVenue.name" name="场地名称" label="场馆名称" input-align="right"
                            error-message-align="right" :placeholder="'请输入场馆名'" :rules="venueFormRule.name" />

                        <!-- 场馆类型选择 -->
                        <van-field v-model="ProjectName" is-link readonly name="picker" label="场馆类型" placeholder="点击选择类目"
                            @click="showVenueTypePicker = true" input-align="right" />
                        <van-popup v-model:show="showVenueTypePicker" position="bottom">
                            <van-picker :columns="VenueTypeColumns" @confirm="VenueTypePicked"
                                @cancel="showVenueTypePicker = false" />
                        </van-popup>


                        <van-field v-model="NewVenue.price" label="收费(元/小时)" input-align="right" :placeholder="'请输入价格'"
                            :rules="venueFormRule.price" error-message-align="right" />

                        <van-field v-model="NewVenue.information" rows="2" autosize label="场地简介" type="textarea"
                            maxlength="50" placeholder="请输入简介" show-word-limit input-align="right"/>


                        <van-field name="switch" label="开放/封闭" input-align="right">
                            <template #input>
                                <van-switch v-model="checked" disabled="" />
                            </template>
                        </van-field>




                        <!-- 按钮 -->
                        <div style="margin: 16px;">
                            <van-button round block type="primary" native-type="submit">
                                确认修改
                            </van-button>
                        </div>
                    </van-form>

                </van-cell-group>
            </div>
        </van-popup>
    </div>
</template>

<script>
import { useRouter } from 'vue-router';
import axios from 'axios';
import { onMounted, ref, nextTick, onBeforeMount } from 'vue';
import { showFailToast, showSuccessToast, showToast, showConfirmDialog } from 'vant';
export default {
    setup() {
        const router = useRouter();
        const onClickLeft = () => {
            router.go(-1);
        };
        const goToPage = (path) => {
            console.log(path);
            router.push(path);
        };

        const venues = ref([])
        const exist_data = ref()
        const showAddNewVenue = ref(false)
        const checked = ref(true)
        const showVenueTypePicker = ref(false)
        const ProjectName = ref('')
        const VenueTypeColumns = [
            { text: '篮球', value: '1' ,pic:'/src/assets/imgs/basketball.jpeg'},
            { text: '羽毛球', value: '2' ,pic:'/src/assets/imgs/badminton.jpg'},
            { text: '游泳', value: '3' ,pic:'/src/assets/imgs/swiming.jpg'},
            { text: '足球', value: '4' ,pic:'/src/assets/imgs/football.jpeg'},
            { text: '乒乓球', value: '5' ,pic:'/src/assets/imgs/tabletennis.jpg'},
            { text: '网球', value: '6' ,pic:'/src/assets/imgs/tennis.jpeg'},
            { text: '桌球', value: '7' ,pic:'/src/assets/imgs/billiards.jpg'}
        ];
        const NewVenue = ref({
            addtime: Date,
            information: String,
            name: String,
            pic: String,
            price: Number,
            projectId: Number,
            stars: Number,
            state: Number
        })
        onBeforeMount(async () => {
            await nextTick(); // 等待 DOM 更新
            axios.get('http://localhost:8081/gym/getAllVenues'
            )
                .then(response => {
                    if (response.data.code === 20041) {
                        venues.value = response.data;
                        console.log(response.data)
                        console.log("vvvvv")
                        console.log(venues.value)
                        console.log("123", response.data.code)
                        exist_data.value = true
                    } else {
                        console.log("空数据")
                        exist_data.value = false
                    }
                })
                .catch(error => {
                    console.error(error);
                });

            NewVenue.value = {
                ...NewVenue,
                addtime: new Date(),
                information: "",
                name: "",
                pic: "",
                price: null,
                projectId: 0,
                stars: 5,
                state: 1
            }
        })

        const getItems = (id) => {
            axios.get('http://localhost:8081/gym/getVenues', {
                params: { project_id: id }
            })
                .then(response => {
                    if (response.data.code === 20041) {
                        venues.value = response.data;
                        console.log(response.data)
                        console.log("vvvvv")
                        console.log(venues.value)
                        console.log("123", response.data.code)
                        exist_data.value = true
                    } else {
                        console.log("空数据")
                        exist_data.value = false
                    }
                })
                .catch(error => {
                    console.error(error);
                });
        }

        const deleteVenue = (venueId) => {
            console.log(venueId)
            showConfirmDialog({
                title: '温馨提示',
                message:
                    '请确认是否下架此场馆',
            }).then(() => {
                // on confirm
                console.log("确认删除场馆数据")
                axios.post('http://localhost:8081/gym/deleteVenueInfo',null,{params:{VenueId:venueId}})
                .then(response => {
                    if(response.data.code === 20021) {
                        console.log("删除成功")
                        venues.value = response.data;
                        console.log("vvvv",venues.value)
                        showSuccessToast("删除成功")
                    }else {
                        console.log("删除失败")
                        showFailToast("系统出错了")
                    }
                })
            })
                .catch(() => {
                    // on cancel
                });
        }


        const picNewValue = ref([
            { url: '/src/assets/imgs/basketball_1.jpg', isImage: true }
        ]);


        //校验
        const pricepattern = /^(?!0$)(?!0\d)[0-9]{1,3}$/;
        const venueFormRule = ref({
            name: [{ required: true, message: "请输入场馆名称" }],
            price: [{ validator: (value) => pricepattern.test(value), message: "价格限制0~999" }]
        })


        const VenueTypePicked = ({ selectedOptions }) => {
            console.log(selectedOptions[0]?.value)
            NewVenue.value.projectId = selectedOptions[0]?.value;
            const name = VenueTypeColumns.find(item => item.value === selectedOptions[0]?.value)
            console.log(name)
            ProjectName.value = name.text;

            NewVenue.value.pic = name.pic;

            showVenueTypePicker.value = false;
        }

        const addNewVenue = (values) => {
            console.log(NewVenue)
            axios.post("http://localhost:8081/gym/addNewVenueInfo", NewVenue.value)
                .then(response => {
                    if (response.data.code === 20011) {
                        venues.value = response.data;
                        console.log("add success")
                        showAddNewVenue.value = false;
                    } else {
                        console.log("add failure")
                    }
                }).catch(error => {
                    // 处理请求错误
                    console.error('Error while sending the request:', error);
                    showFailToast("系统出错了")
                })
        }

        return {
            onClickLeft, getItems, venues, exist_data,
            goToPage, addNewVenue, showAddNewVenue, picNewValue,
            pricepattern, venueFormRule, NewVenue, checked,
            showVenueTypePicker, VenueTypePicked, VenueTypeColumns, ProjectName,deleteVenue
        };
    }
}
</script>

